INSERT INTO regular_expressions (name, pattern, description) VALUES ('IMAX', '\b((?<!NON[ ._-])IMAX)\b', 'Matches any IMAX release. This includes:
- Any movie shot with IMAX in mind and henceforth tagged as `IMAX`
- IMAX Enchanced digital releases found on `Disney + / Bravia Core`');
INSERT INTO regular_expressions (name, pattern, description) VALUES ('IMAX Enhanced', '^(?=.*\b((DSNP|BC|B?CORE)\b|Disney\+)(?=.*\bWEB[ ._-]?(DL|Rip)\b))(?=.*\b((?<!NON[ ._-])IMAX)\b)|^(?=.*\b(IMAX[ ._-]Enhanced)\b)', 'Matches IMAX releases from specific digital sources.

- Checks for WEBs from `Disney+` or `Bravia Core`
- Ensures "IMAX" appears (with optional "Enhanced" suffix) but not when preceded by "NON"');
