INSERT INTO custom_formats (name, description) VALUES ('WEBRip', 'A WEBRip is a video file created by capturing and potentially re-encoding content from streaming services or web platforms. It can be produced through several methods: capturing via HDMI with HDCP stripping (often at higher resolutions like 4K then encoding down to 1080p, resulting in larger file sizes due to the high-quality source), re-encoding from Web-DL sources when they offer superior quality to physical media, or through traditional web capture methods without re-encoding. Unlike Web-DLs which are direct downloads of the source file, WEBRips involve some form of capture or conversion process, which can affect quality and file size depending on the method and settings used.');
