INSERT INTO custom_formats (name, description) VALUES ('x265 (HD)', 'This matches all 720/1080p (HD) releases that are encoded in x265. Change the score of this format to 0 or remove entirely to allow H265 releases.');
INSERT INTO custom_formats (name, description) VALUES ('x265 (no HDR DV)', 'This blocks most 720/1080p (HD) releases that are encoded in x265, But it will allow 720/1080p x265 releases if they have HDR and/or DV

Make sure to remove the "x265" format from a profile before adding this one, score this format at -10000.');
