-- Quality Profiles

INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('1080p LQ', '- This profile is for **SIDCA** (Sh*t I Don''t Care About). The primary tier and LQ groups are not scored to allow "low quality" releases. For example, user requests "Keeping Up with the Kardashians" and you would prefer to save as much storage space as humanly possible so this user can watch this "show".
- You can expect to grab **MeGusta** releases 99% of the time.
- AV1 and x265 codecs are allowed and scored for preference of x265. **NOTE! you may encounter transcoding if the client side does not support these codecs.**', 1, 1, 10000, 1);
INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('Anime 1080p', 'Based on the TRaSH Guides Anime Profile, focusing on media that has Dual Audio.
- This profile will grab between a SDTV - 1080p Bluray file.
- You will be preferring Dual Audio media (ie including English along with original language). If you''d prefer to **only** have the original language (Japanese), remove the Dual Audio format and set you language settings in this profile to Advanced - Must Include - Japanese.
- If you''d prefer to always grab Dual Audio releases, change the Dual Audio format score from 101 to 500', 1, 0, 10000, 1);
INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('Movies 1080p', 'This profile focuses on streaming optimized sources with little to no transcoding needed and is recommended for the average user or if you **do not** use a dedicated streaming box. (i.e. AppleTV, NVIDIA Shield, etc)
- This profile is recommended for a set-it-and-forget-it setup.
- This profile will prefer streaming optimized releases groups like **BHDStudio** and **hallowed**.
- This profile does not allow releases with HD Audio to ensure direct-play compatibility.', 1, 750, 10000, 1);
INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('Movies 1080p HQ', 'This profile is like the primary Movie profile, but with merged source qualities. This results in higher-quality, WEB releases being preferred. This usually results in higher-quality audio, higher video bitrates and 30% larger file size.
- This profile is recommended for a set-it-and-forget-it setup.
- This profile will fall back to streaming optimized releases groups like **BHDStudio** and **hallowed**.
- This profile will allow HD audio like TrueHD, DTS-X, etc but only if the source is WEB-DL', 1, 750, 10000, 1);
INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('Movies 2160p', 'This profile focuses on streaming optimized sources with little to no transcoding needed and is recommended for the average user or if you **do not** use a dedicated streaming box. (i.e. AppleTV, NVIDIA Shield, etc)
- This profile is recommended for a set-it-and-forget-it setup.
- This profile will prefer streaming optimized releases groups like **BHDStudio** and **hallowed**.
- This profile does not allow releases with HD Audio to ensure direct-play compatibility.
- Releases without HDR fallback will be scored negatively to ensure playability across platforms.', 1, 1000, 10000, 1);
INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('Movies 2160p HQ', 'This profile is like the primary Movie profile, but with merged source qualities. This results in higher-quality, WEB releases being preferred. This usually results in higher-quality audio, higher video bitrates and 30% larger file size.
- This profile is recommended for a set-it-and-forget-it setup.
- This profile prefers 4K releases with **HDR** and **Dolby Vision**.
- This profile will fall back to streaming optimized releases groups like **BHDStudio** and **hallowed**.
- This profile will allow HD audio like TrueHD, DTS-X, etc but only if the source is WEB-DL
- Releases **without** HDR fallback are not allowed.', 1, 1000, 10000, 1);
INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('TV 1080p', 'Based on the TRaSH Guides WEB-1080p (Alternative) profile, focusing on balanced quality/file size.
- This profile is recommended for a set-it-and-forget-it setup.
- Ensure you add a **[delay profile](https://wiki.servarr.com/sonarr/settings#:~:text=%C2%B6-,Delay%20Profiles,-Delay%20profiles%20allow)** to your setup. I prefer 60 minutes, but adjust this as needed.', 1, 0, 10000, 1);
INSERT INTO quality_profiles (name, description, upgrades_allowed, minimum_custom_format_score, upgrade_until_score, upgrade_score_increment)
VALUES ('TV 2160p', 'Based on the TRaSH Guides WEB-1080p (Alternative) profile, focusing on balanced quality/file size.
- This profile is recommended for a set-it-and-forget-it setup.
- Ensure you add a **[delay profile](https://wiki.servarr.com/sonarr/settings#:~:text=%C2%B6-,Delay%20Profiles,-Delay%20profiles%20allow)** to your setup. I prefer 60 minutes, but adjust this as needed.', 1, 0, 10000, 1);

